59	// global signal
60	    input   logic                                 clk;
61	    input   logic                                 rst_n;
62	
63	// vector instruction and scalar operand input. 
64	    input   logic         [`ISSUE_LANE-1:0]       insts_valid_rvs2cq;
65	    input   RVVCmd        [`ISSUE_LANE-1:0]       insts_rvs2cq;
