71	    output  logic         [`NUM_LSU-1:0]          uop_lsu_valid_rvv2lsu;
72	    output  UOP_RVV2LSU_t [`NUM_LSU-1:0]          uop_lsu_rvv2lsu;
73	    input   logic         [`NUM_LSU-1:0]          uop_lsu_ready_lsu2rvv;
74	  // LSU feedback to RVV
