76	    input   UOP_LSU2RVV_t [`NUM_LSU-1:0]          uop_lsu_lsu2rvv;
77	    output  logic         [`NUM_LSU-1:0]          uop_lsu_ready_rvv2lsu;
78	
79	// RT to XRF. 
80	    output  logic         [`NUM_RT_UOP-1:0]       rt_xrf_valid_rvv2rvs;
81	    output  RT2RVS_t      [`NUM_RT_UOP-1:0]       rt_rvs_rvv2rvs;
82	    input   logic         [`NUM_RT_UOP-1:0]       rt_rvs_ready_rvs2rvv;
83	
84	// RT to FRF. 
85	`ifdef ZVE32F_ON
86	    output  logic [`NUM_RT_UOP-1:0]                           async_frd_valid;
87	    output  logic [`NUM_RT_UOP-1:0][`REGFILE_INDEX_WIDTH-1:0] async_frd_addr;
88	    output  logic [`NUM_RT_UOP-1:0][`XLEN-1:0]                async_frd_data;
89	    input   logic [`NUM_RT_UOP-1:0]                           async_frd_ready;
90	`endif
91	
92	// RT to VCSR.vxsat
93	    output  logic                                 wr_vxsat_valid;
94	    output  logic         [`VCSR_VXSAT_WIDTH-1:0] wr_vxsat;
95	    input   logic                                 wr_vxsat_ready;
96	
97	`ifdef ZVE32F_ON
98	// RT to FCSR
99	    output  logic                                 rt2fcsr_write_valid;
100	    output  RVFEXP_t                              rt2fcsr_write_data;
101	    input   logic                                 fcsr2rt_write_ready;
102	`endif
103	
104	// exception handler
105	  // trap signal handshake
106	    input   logic                                 trap_valid_rvs2rvv;
107	    output  logic                                 trap_ready_rvv2rvs;    
108	  // the vcsr of last retired uop in last cycle
109	    output  logic                                 vcsr_valid;
110	    output  RVVConfigState                        vector_csr;
111	    input   logic                                 vcsr_ready;
112	
113	// retire information
114	    output  logic     [`NUM_RT_UOP-1:0]           rd_valid_rob2rt_o;
115	    output  ROB2RT_t  [`NUM_RT_UOP-1:0]           rd_rob2rt_o;
116	
117	// rvv_backend is not active.(IDLE)
118	    output  logic                                 rvv_idle;
119	
120	
121	// ---internal signals definition-------------------------------------
122	  // RVV frontend to command queue
123	    logic         [`ISSUE_LANE-1:0]       cq_almost_full;
124	    logic         [`ISSUE_LANE-1:0]       insts_ready;  
125	    logic         [$clog2(`CQ_DEPTH):0]   used_count_cq; 
