130	    logic         [`NUM_DE_INST-1:0]      fifo_almost_empty_cq2de;
131	    logic         [`NUM_DE_INST-1:0]      pop_de2cq;
132	
133	    logic         [`NUM_DE_INST-1:0]      lcmd_valid_de2lcq;
134	    LCMD_t        [`NUM_DE_INST-1:0]      lcmd_de2lcq;
