139	    logic         [`NUM_DE_INST-1:0]      fifo_almost_empty_lcq2de;
140	    logic         [`NUM_DE_INST-1:0]      fifo_almost_full_lcq2de;
141	    logic         [`NUM_DE_INST-1:0]      pop_de2lcq;
