144	    UOP_QUEUE_t   [`NUM_DE_UOP-1:0]       uop_de2uq;
145	    logic         [`NUM_DE_UOP-1:0]       fifo_almost_full_uq2de;
146	    logic         [`NUM_DE_UOP-1:0]       uq_ready;
147	  // Uop queue to dispatch
