149	    logic         [`NUM_DP_UOP-1:0]       uq_almost_empty;
150	    logic         [`NUM_DP_UOP-1:0]       uop_valid_uop2dp;
151	    UOP_QUEUE_t   [`NUM_DP_UOP-1:0]       uop_uop2dp;
152	    logic         [`NUM_DP_UOP-1:0]       uop_ready_dp2uop;
153	
154	  // Dispatch to RS
155	    // ALU_RS
156	    logic         [`NUM_DP_UOP-1:0]       alu_rs_almost_full;
157	    logic         [`NUM_DP_UOP-1:0]       rs_valid_dp2alu;
158	    ALU_RS_t      [`NUM_DP_UOP-1:0]       rs_dp2alu;
159	    logic         [`NUM_DP_UOP-1:0]       rs_ready_alu2dp;
160	    // PMTRDT_RS  
161	    logic         [`NUM_DP_UOP-1:0]       pmtrdt_rs_almost_full;
162	    logic         [`NUM_DP_UOP-1:0]       rs_valid_dp2pmtrdt;
163	    PMT_RDT_RS_t  [`NUM_DP_UOP-1:0]       rs_dp2pmtrdt;
164	    logic         [`NUM_DP_UOP-1:0]       rs_ready_pmtrdt2dp;
165	    // MUL_RS
