167	    logic         [`NUM_DP_UOP-1:0]       rs_valid_dp2mul;
168	    MUL_RS_t      [`NUM_DP_UOP-1:0]       rs_dp2mul;
169	    logic         [`NUM_DP_UOP-1:0]       rs_ready_mul2dp;
