719	        .T            (UOP_RVV2LSU_t),
720	        .M            (`NUM_DP_UOP),
721	        .N            (`NUM_LSU),
722	        .DEPTH        (`LSUMAP_DEPTH),
723	        .ASYNC_RSTN   (1'b1),
