764	        .T            (LSU_MAP_INFO_t),
765	        .M            (`NUM_DP_UOP),
766	        .N            (`NUM_LSU),
767	        .DEPTH        (`LSU_RS_DEPTH),
768	        .ASYNC_RSTN   (1'b1),
769	        .CHAOS_PUSH   (1'b1)
770	    ) u_lsu_map_info (
771	      // global
772	        .clk          (clk),
773	        .rst_n        (rst_n),
774	      // write
775	        .push         (mapinfo_valid_dp2lsu),
776	        .datain       (mapinfo_dp2lsu),
777	      // read
778	        .pop          (pop_mapinfo),
779	        .dataout      (mapinfo),
780	      // fifo status
781	        .full         (),
