783	        .empty        (mapinfo_empty),
784	        .almost_empty (mapinfo_almost_empty),
785	        .clear        (trap_flush_rvv),
786	        .fifo_data    (),
787	        .wptr         (),
788	        .rptr         (),
789	        .entry_count  ()
790	    );
791	
792	    assign mapinfo_ready_lsu2dp = ~mapinfo_almost_full;
793	
794	  // trap handler
795	    // make sure all lsu uops before the trapping uop have been pushed into LSU_RES_FIFO 
796	    assign trap_en = trap_valid_rvs2rvv & (uop_lsu_valid_lsu2rvv=='b0) & (!lsu_res_almost_full[0]) & (!is_trapping);
797	
798	    cdffr
799	    trap_valid
800	    (
801	      .clk            (clk),
